import assert from 'tjs:assert';
import path from 'tjs:path';

async function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

const encoder = new TextEncoder();
const tmpDir = await tjs.makeTempDir('fswatch_gcXXXXXX');
const file = path.join(tmpDir, 'test.txt');
await tjs.writeFile(file, encoder.encode('start'));

let eventCount = 0;
const closeWatcher = tjs.watch(file, () => {
    eventCount++;
    closeWatcher.close();
});
closeWatcher.close();

tjs.watch(file, () => {
    eventCount++;
});

await sleep(100);
for (let i = 0; i < 10; i++) {
    await tjs.writeFile(file, encoder.encode(`change-${i}`));
    await sleep(100);
    if (eventCount > 0) {
        break;
    }
}

await tjs.remove(file);
await tjs.remove(tmpDir);

assert.ok(eventCount > 0, 'unreferenced FileWatcher should stay active until close');

